SELECT "APP_GROUP_ID", TO_DATE(TO_TIMESTAMP("TIME")) AS session_start_day, COUNT(DISTINCT "USER_ID") AS unique_users FROM "BRAZE_USER_EVENT_DEMO_DATASET"."PUBLIC"."USERS_BEHAVIORS_APP_SESSIONSTART_VIEW" WHERE TO_DATE(TO_TIMESTAMP("TIME")) BETWEEN DATE '2023-06-01' AND DATE '2023-06-07' GROUP BY "APP_GROUP_ID", session_start_day ORDER BY "APP_GROUP_ID", session_start_day